arguments.argument:
if global.gamePaused=false
{
  event_inherited()
  if bActive=true and bIsSucked=0
  {
    moveWave+=pi/60
    y+=sin(moveWave)
    x-=runAcc
    
    missileTime+=1
    if missileTime>=missileDelay and x>32
    {
      var tAtk;
      tAtk=instance_create(x+6,y-4,oCW_SpinMissile)
      tAtk.atkPower=atkPower; tAtk.turnDir=2
      tAtk=instance_create(x+6,y+4,oCW_SpinMissile)
      tAtk.atkPower=atkPower; tAtk.turnDir=-2
      missileTime=0
    }
    
    if x<=-32 {instance_destroy()}
  }
  enemyStepEvent()
}
